def max_profit(prices):
    if not prices: return 0
    min_p = prices[0]
    max_f = 0
    for p in prices:
        min_p = min(min_p, p)
        max_f = max(max_f, p - min_p)
    return max_f

if __name__ == "__main__":
    print(f"Prices [7, 6, 1, 3]: {max_profit([7, 6, 1, 3])}")
